function mk(idBase, category, list) {
  return list.map((item, i) => {
    const sale = Number(item.sale.toFixed(2))
    const original = Number((item.original ?? sale * 1.22).toFixed(2))
    const discount = Math.max(0, Math.round((1 - sale / original) * 100))
    return { id: idBase + i, category, image: item.image, originalPrice: original, salePrice: sale, discount, name: item.name }
  })
}

